content.outputFormat:
For each test case output a single line containing one integer:
1 – the given board is reachable and the game is already finished (either a win for X or O, or a draw);
2 – the board is reachable and the game can still continue (no winner yet and at least one empty cell);
3 – the board is not reachable from an empty board following the rules of the game.

code.C:
#include <stdio.h>
#include <string.h>

int win(char b[3][3], char p) {
    // rows
    for (int i = 0; i < 3; ++i) if (b[i][0]==p && b[i][1]==p && b[i][2]==p) return 1;
    // cols
    for (int j = 0; j < 3; ++j) if (b[0][j]==p && b[1][j]==p && b[2][j]==p) return 1;
    // diagonals
    if (b[0][0]==p && b[1][1]==p && b[2][2]==p) return 1;
    if (b[0][2]==p && b[1][1]==p && b[2][0]==p) return 1;
    return 0;
}

int main(){
    int T; if (scanf("%d", &T)!=1) return 0;
    char line[5];
    while (T--) {
        char board[3][3];
        for (int i=0;i<3;++i){
            scanf("%s", line);
            for (int j=0;j<3;++j) board[i][j]=line[j];
        }
        int cntX=0,cntO=0,cntE=0;
        for (int i=0;i<3;++i) for (int j=0;j<3;++j){
            if (board[i][j]=='X') cntX++; else if (board[i][j]=='O') cntO++; else cntE++;
        }
        int winX = win(board,'X');
        int winO = win(board,'O');
        int ans;
        if (!(cntX==cntO || cntX==cntO+1)) ans=3;
        else if (winX && winO) ans=3;
        else if (winX) ans = (cntX==cntO+1)?1:3;
        else if (winO) ans = (cntX==cntO)?1:3;
        else if (cntE==0) ans=1; // draw
        else ans=2; // game can continue
        printf("%d\n", ans);
    }
    return 0;
}

