    for(int j=0;j<3;++j) if(b[0][j]==p && b[1][j]==p && b[2][j]==p) return true;
    if(b[0][0]==p && b[1][1]==p && b[2][2]==p) return true;
    if(b[0][2]==p && b[1][1]==p && b[2][0]==p) return true;
    return false;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        array<array<char,3>,3> board;
        string s;
        for(int i=0;i<3;++i){
            cin>>s;
            for(int j=0;j<3;++j) board[i][j]=s[j];
        }
        int cntX=0,cntO=0,cntE=0;
        for(int i=0;i<3;++i) for(int j=0;j<3;++j){
            if(board[i][j]=='X') ++cntX;
            else if(board[i][j]=='O') ++cntO;
            else ++cntE;
        }
        bool winX=win(board,'X');
        bool winO=win(board,'O');
        int ans;
        if(!(cntX==cntO || cntX==cntO+1)) ans=3;
        else if(winX && winO) ans=3;
        else if(winX) ans = (cntX==cntO+1)?1:3;
        else if(winO) ans = (cntX==cntO)?1:3;
        else if(cntE==0) ans=1; // draw
        else ans=2; // continue
        cout<<ans<<"\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static boolean win(char[][] b, char p) {
        for (int i = 0; i < 3; i++) if (b[i][0]==p && b[i][1]==p && b[i][2]==p) return true;
        for (int j = 0; j < 3; j++) if (b[0][j]==p && b[1][j]==p && b[2][j]==p) return true;
        if (b[0][0]==p && b[1][1]==p && b[2][2]==p) return true;
        if (b[0][2]==p && b[1][1]==p && b[2][0]==p) return true;
        return false;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            char[][] board = new char[3][3];
            for (int i = 0; i < 3; i++) {
                String line = br.readLine();
                while (line != null && line.length() == 0) line = br.readLine(); // skip empty lines
                for (int j = 0; j < 3; j++) board[i][j] = line.charAt(j);
            }
            int cntX = 0, cntO = 0, cntE = 0;
            for (int i = 0; i < 3; i++)
                for (int j = 0; j < 3; j++) {
                    if (board[i][j] == 'X') cntX++;
                    else if (board[i][j] == 'O') cntO++;
                    else cntE++;
                }
            boolean winX = win(board, 'X');
            boolean winO = win(board, 'O');
            int ans;
            if (!(cntX == cntO || cntX == cntO + 1)) ans = 3;
            else if (winX && winO) ans = 3;
            else if (winX) ans = (cntX == cntO + 1) ? 1 : 3;
            else if (winO) ans = (cntX == cntO) ? 1 : 3;
            else if (cntE == 0) ans = 1; // draw
            else ans = 2; // can continue
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

