const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
const T = parseInt(input[pos++], 10);
let results = [];
function win(board, p) {
  const lines = [
    [[0,0],[0,1],[0,2]],
    [[1,0],[1,1],[1,2]],
    [[2,0],[2,1],[2,2]],
    [[0,0],[1,0],[2,0]],
    [[0,1],[1,1],[2,1]],
    [[0,2],[1,2],[2,2]],
    [[0,0],[1,1],[2,2]],
    [[0,2],[1,1],[2,0]]
  ];
  return lines.some(line => line.every(([r,c]) => board[r][c] === p));
}
for (let tc = 0; tc < T; ++tc) {
  let board = [Array.from(input[pos++]), Array.from(input[pos++]), Array.from(input[pos++])];
  let cntX = 0, cntO = 0, cntE = 0;
  for (let i = 0; i < 3; ++i) {
    for (let j = 0; j < 3; ++j) {
      const ch = board[i][j];
      if (ch === 'X') cntX++; else if (ch === 'O') cntO++; else cntE++;
    }
  }
  const winX = win(board, 'X');
  const winO = win(board, 'O');
  let ans;
  if (!(cntX === cntO || cntX === cntO + 1)) ans = 3;
  else if (winX && winO) ans = 3;
  else if (winX) ans = (cntX === cntO + 1) ? 1 : 3;
  else if (winO) ans = (cntX === cntO) ? 1 : 3;
  else if (cntE === 0) ans = 1;
  else ans = 2;
  results.push(String(ans));
}
console.log(results.join('\n'));

